sql:
SELECT feedback_id, fuel_type_id, color_id, vehicle_id, customer_id
FROM customer_feedback
WHERE feedback_id > 10 AND is_anonymous = 0;

external_knowledge:
- 'more seasoned subscribers' refers to customers who are 30 years old or older and are subscribed to the newsletter;
- 'given their thoughts on vehicles via the website' means that the feedback source is specifically the website;
- 'high opinion of the price and safety aspects' implies that the average ratings for both price and safety are 4 out of 5 or higher.

sql:
SELECT color_name 
FROM colors 
WHERE color_id = 1;

SELECT cf.customer_satisfaction_score, r.region_name
FROM customer_feedback cf
INNER JOIN regions r ON cf.region_id = r.region_id;

SELECT 
    (SELECT AVG(customer_satisfaction_score) 
     FROM customer_feedback cf 
     JOIN regions r ON cf.region_id = r.region_id 
     WHERE r.region_name = 'North America'
    ) AS North_America_average,
    (SELECT AVG(customer_satisfaction_score) 
     FROM customer_feedback
    ) AS Total_average;

external_knowledge:
- 'seafarers' metaphorically refers to customers providing feedback;
- 'navigating the currents' represents using electric self-driving vehicles;
- 'hoisted on their sails' symbolizes giving feedback;
- 'stars' represent the customer satisfaction scores;
- 'positive feedback' is feedback with a score of 4 or 5;
- 'overall voyages' refer to the total number of feedbacks provided.

sql:
SELECT AVG(customer_satisfaction_score) AS AverageSatisfactionScore
FROM customer_feedback
WHERE safety_rating >= 4 AND resale_value_rating >= 4;

SELECT feedback_id, customer_id, vehicle_id, price_rating, safety_rating, exterior_looks_rating, space_comfort_rating, technology_rating, after_sales_service_rating, resale_value_rating, fuel_efficiency_rating, maintenance_rating, test_drive_rating, product_reviews_rating, testimonials, feedback_date, feedback_version, region_id, customer_satisfaction_score, is_anonymous, source_of_feedback
FROM customer_feedback
WHERE region_id IN (1, 2);

